public class TreeNode {
    int val;
    TreeNode left;
    TreeNode right;
}

public TreeNode increasingBST(TreeNode root) {
    TreeNode dummy = new TreeNode(0);
    TreeNode prev = dummy;
    inorder(root, prev);
    return dummy.right;
}

public void inorder(TreeNode node, TreeNode prev) {
    if (node == null) return;

    inorder(node.left, prev);
    prev.right = node;
    prev = node;
    node.left = null;
    inorder(node.right, prev);
}
```


